# Colors module - provides color enum and color operations

enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3
    YELLOW = 4

class ColorPalette:
    _colors: list[Color]

    def __init__(self):
        self._colors = []

    def add(self, color: Color) -> None:
        self._colors.append(color)

    def count(self) -> int:
        return len(self._colors)

    def names(self) -> list[str]:
        result: list[str] = []
        for c in self._colors:
            result.append(c.name)
        return result

