# Shapes module - provides abstract base classes and interfaces

@abstract
class Shape:
    @abstract
    def area(self) -> float: ...

    @abstract
    def describe(self) -> str: ...

interface Drawable:
    def draw(self) -> None: ...

@abstract
class ColoredShape(Shape):
    _color: int

    def __init__(self, color: int):
        self._color = color

    def color_value(self) -> int:
        return self._color

