# Extended shapes - concrete implementations using cross-module inheritance

from shapes import Shape, ColoredShape, Drawable
from colors import Color

class Rectangle(ColoredShape, Drawable):
    _width: float
    _height: float

    def __init__(self, width: float, height: float, color: Color):
        super().__init__(color.value)
        self._width = width
        self._height = height

    @override
    def area(self) -> float:
        return self._width * self._height

    @override
    def describe(self) -> str:
        return f"Rectangle({self._width}, {self._height})"

    def draw(self) -> None:
        desc: str = self.describe()
        print(f"Drawing: {desc}")

    def get_dimensions(self) -> tuple[float, float]:
        return (self._width, self._height)

class Circle(ColoredShape, Drawable):
    _radius: float

    def __init__(self, radius: float, color: Color):
        super().__init__(color.value)
        self._radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self._radius * self._radius

    @override
    def describe(self) -> str:
        return f"Circle(radius={self._radius})"

    def draw(self) -> None:
        desc: str = self.describe()
        print(f"Drawing: {desc}")
